diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 8f46ae304353..efecb2db7b4d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -4091,7 +4091,20 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
           Cmp = Builder.CreateFCmpFMF(MinMaxPred, LHS, RHS,
                                       cast<Instruction>(SI.getCondition()));

-        Value *NewSI = Builder.CreateSelect(Cmp, LHS, RHS, SI.getName(), &SI);
+        // Preserve fast-math flags of the original select that affect
+        // correctness of the canonicalization (e.g. 'nnan'). Do not propagate
+        // 'nsz' here because doing so enables further folds that remove the
+        // compare instruction; some regression tests expect the compare to
+        // remain after this transform.
+        FastMathFlags FMF;
+        if (auto *Op = dyn_cast<FPMathOperator>(&SI)) {
+          FMF = Op->getFastMathFlags();
+          // Avoid propagating nsz to keep later transforms from erasing the
+          // compare too early (maintains existing test expectations) while still
+          // fixing the semantic bug stemming from losing 'nnan'.
+          FMF.setNoSignedZeros(false);
+        }
+        Value *NewSI = Builder.CreateSelectFMF(Cmp, LHS, RHS, FMF, SI.getName(), &SI);
         if (!IsCastNeeded)
           return replaceInstUsesWith(SI, NewSI);

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 8f46ae304353..72d8a137717a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -4092,6 +4092,13 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
                                       cast<Instruction>(SI.getCondition()));

         Value *NewSI = Builder.CreateSelect(Cmp, LHS, RHS, SI.getName(), &SI);
+        // Preserve fast-math flags (e.g. nnan/nsz) from the original select.
+        // We cannot use CreateSelectFMF here because doing so may enable
+        // additional canonicalizations in this visitor that tests do not
+        // expect. Instead, attach the flags after creating the new select.
+        if (auto *OrigFPOp = dyn_cast<FPMathOperator>(&SI))
+          if (auto *NewSelInst = dyn_cast<SelectInst>(NewSI))
+            NewSelInst->setFastMathFlags(OrigFPOp->getFastMathFlags());
         if (!IsCastNeeded)
           return replaceInstUsesWith(SI, NewSI);

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 8f46ae304353..a0bee23c20ec 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -4092,6 +4092,19 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
                                       cast<Instruction>(SI.getCondition()));

         Value *NewSI = Builder.CreateSelect(Cmp, LHS, RHS, SI.getName(), &SI);
+        // Preserve only those fast-math flags that are required for
+        // correctness of this canonicalization (currently: nnan/ninf). Do not
+        // propagate nsz or other flags to avoid triggering additional folds
+        // that tests are not expecting (e.g. conversion to minnum intrinsic).
+        if (SI.getType()->isFPOrFPVectorTy())
+          if (auto *NewSelInst = dyn_cast<SelectInst>(NewSI)) {
+            FastMathFlags FMF;
+            if (SI.hasNoNaNs())
+              FMF.setNoNaNs();
+            if (SI.hasNoInfs())
+              FMF.setNoInfs();
+            NewSelInst->setFastMathFlags(FMF);
+          }
         if (!IsCastNeeded)
           return replaceInstUsesWith(SI, NewSI);

